import { useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import Header from '../components/Header';
import { allProducts } from '../data/mockData';
import styles from './ProductDetailPage.module.css';

export default function ProductDetailPage() {
  const { id } = useParams();
  const product = allProducts.find((p) => p.id === Number(id));

  const [activeImg, setActiveImg] = useState(0);
  const [selectedSize, setSelectedSize] = useState(null);
  const [quantity, setQuantity] = useState(0);
  const [openAccordion, setOpenAccordion] = useState(null);

  if (!product) {
    return (
      <>
        <Header />
        <div style={{ textAlign: 'center', padding: '200px 0', fontFamily: 'var(--font-en)' }}>
          <p>Product not found.</p>
          <Link to="/" style={{ color: '#999', fontSize: 12 }}>Back to Home</Link>
        </div>
      </>
    );
  }

  const images = product.detailImages || [product.imageUrl];
  const sizeOptions = product.sizes?.map((s) => s.size) || [];
  const totalPrice = selectedSize ? product.price * Math.max(quantity, 1) : 0;
  const totalQty = selectedSize ? Math.max(quantity, 1) : 0;

  const handleSizeClick = (size) => {
    setSelectedSize(size);
    setQuantity(1);
  };

  const toggleAccordion = (key) => {
    setOpenAccordion(openAccordion === key ? null : key);
  };

  // SIZE (CM) 테이블 데이터 생성
  const sizeTableKeys = product.sizes?.length
    ? Object.keys(product.sizes[0]).filter((k) => k !== 'size')
    : [];

  const formatKey = (key) =>
    key.replace(/([A-Z])/g, ' $1').replace(/^./, (s) => s.toUpperCase());

  // material 텍스트
  const materialLines = product.material
    ? Object.entries(product.material).map(
        ([key, val]) => `${key.charAt(0).toUpperCase() + key.slice(1)}: ${val}`
      )
    : [];

  return (
    <>
      <Header />
      <div className={styles.page}>
        <div className={styles.productSection}>
          {/* ── 왼쪽: 썸네일 + 히어로 이미지 ── */}
          <div className={styles.imageArea}>
            <div className={styles.thumbnails}>
              {images.map((src, i) => (
                <button
                  key={i}
                  className={`${styles.thumb} ${i === activeImg ? styles.thumbActive : ''}`}
                  onClick={() => setActiveImg(i)}
                >
                  <img src={src} alt={`${product.name} ${i + 1}`} />
                </button>
              ))}
            </div>
            <div className={styles.hero}>
              <img
                key={activeImg}
                src={images[activeImg]}
                alt={product.name}
                className={styles.heroImg}
              />
            </div>
          </div>

          {/* ── 오른쪽: 상품 정보 ── */}
          <div className={styles.infoArea}>
            <p className={styles.productCode}>{product.code}</p>
            <h1 className={styles.productName}>
              {product.name} ({product.color})
            </h1>

            <div className={styles.priceRow}>
              <span className={styles.priceLabel}>PRICE</span>
              <span className={styles.priceValue}>
                {product.price.toLocaleString()} {product.currency}
              </span>
            </div>

            {sizeOptions.length > 0 && sizeOptions[0] !== 'OS' && (
              <div className={styles.sizeRow}>
                <span className={styles.sizeLabel}>SIZE</span>
                <div className={styles.sizeButtons}>
                  {sizeOptions.map((size) => (
                    <button
                      key={size}
                      className={`${styles.sizeBtn} ${selectedSize === size ? styles.sizeBtnActive : ''}`}
                      onClick={() => handleSizeClick(size)}
                    >
                      {size}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className={styles.totalRow}>
              <span className={styles.totalLabel}>TOTAL PRICE</span>
              <span className={styles.totalValue}>
                {totalPrice.toLocaleString()}
                <span className={styles.won}>원</span>{' '}
                <span className={styles.qty}>({totalQty}개)</span>
              </span>
            </div>

            <button className={styles.buyBtn}>BUY IT NOW</button>

            <div className={styles.subButtons}>
              <button className={styles.cartBtn}>CART</button>
              <button className={styles.wishBtn}>WISH LIST</button>
            </div>

            {/* ── 아코디언 ── */}
            <div className={styles.accordions}>
              <div className={styles.accordionItem}>
                <button
                  className={styles.accordionHeader}
                  onClick={() => toggleAccordion('detail')}
                >
                  <span>DETAIL</span>
                  <span className={styles.accordionIcon}>
                    {openAccordion === 'detail' ? '−' : '+'}
                  </span>
                </button>
                {openAccordion === 'detail' && (
                  <div className={styles.accordionBody}>
                    <p>{product.description}</p>
                    {product.origin && <p>{product.origin}</p>}
                  </div>
                )}
              </div>

              <div className={styles.accordionItem}>
                <button
                  className={styles.accordionHeader}
                  onClick={() => toggleAccordion('size')}
                >
                  <span>SIZE (CM)</span>
                  <span className={styles.accordionIcon}>
                    {openAccordion === 'size' ? '−' : '+'}
                  </span>
                </button>
                {openAccordion === 'size' && product.sizes && (
                  <div className={styles.accordionBody}>
                    <table className={styles.sizeTable}>
                      <thead>
                        <tr>
                          <th>Size</th>
                          {sizeTableKeys.map((k) => (
                            <th key={k}>{formatKey(k)}</th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {product.sizes.map((row) => (
                          <tr key={row.size}>
                            <td>{row.size}</td>
                            {sizeTableKeys.map((k) => (
                              <td key={k}>{row[k]}</td>
                            ))}
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>

              <div className={styles.accordionItem}>
                <button
                  className={styles.accordionHeader}
                  onClick={() => toggleAccordion('materials')}
                >
                  <span>MATERIALS</span>
                  <span className={styles.accordionIcon}>
                    {openAccordion === 'materials' ? '−' : '+'}
                  </span>
                </button>
                {openAccordion === 'materials' && (
                  <div className={styles.accordionBody}>
                    {materialLines.map((line, i) => (
                      <p key={i}>{line}</p>
                    ))}
                  </div>
                )}
              </div>

              <div className={styles.accordionItem}>
                <button
                  className={styles.accordionHeader}
                  onClick={() => toggleAccordion('care')}
                >
                  <span>HOW TO WASH</span>
                  <span className={styles.accordionIcon}>
                    {openAccordion === 'care' ? '−' : '+'}
                  </span>
                </button>
                {openAccordion === 'care' && product.care && (
                  <div className={styles.accordionBody}>
                    <ul className={styles.careList}>
                      {product.care.map((item, i) => (
                        <li key={i}>{item}</li>
                      ))}
                    </ul>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* ── You May Also Like ── */}
        <div className={styles.recommend}>
          <p className={styles.recommendTitle}>You May Also Like</p>
          <div className={styles.recommendGrid}>
            {allProducts
              .filter((p) => p.id !== product.id)
              .slice(0, 4)
              .map((p) => (
                <Link
                  key={p.id}
                  to={`/product/${p.id}`}
                  className={styles.recommendCard}
                >
                  <div
                    className={styles.recommendImgWrap}
                    style={{ backgroundColor: p.bg }}
                  >
                    <img src={p.detailImages?.[0] || p.imageUrl} alt={p.name} />
                  </div>
                  <p className={styles.recommendName}>
                    {p.name} ({p.color})
                  </p>
                  <p className={styles.recommendPrice}>
                    {p.price.toLocaleString()} {p.currency}
                  </p>
                </Link>
              ))}
          </div>
        </div>
      </div>
    </>
  );
}
